__attribute__((unused)) static void
packetfilter_bpf__assert(struct packetfilter_bpf *s __attribute__((unused)))
{
#ifdef __cplusplus
#define _Static_assert static_assert
#endif
	_Static_assert(sizeof(s->rodata->TIME_WINDOW_NS) == 8, "unexpected size of 'TIME_WINDOW_NS'");
	_Static_assert(sizeof(s->rodata->PACKET_RATE_THRESHOLD) == 4, "unexpected size of 'PACKET_RATE_THRESHOLD'");
	_Static_assert(sizeof(s->rodata->REQ_RATE_THRESHOLD) == 4, "unexpected size of 'REQ_RATE_THRESHOLD'");
	_Static_assert(sizeof(s->rodata->LATENCY_THRESHOLD_MS) == 4, "unexpected size of 'LATENCY_THRESHOLD_MS'");
	_Static_assert(sizeof(s->rodata->CONN_RATE_THRESHOLD) == 4, "unexpected size of 'CONN_RATE_THRESHOLD'");
#ifdef __cplusplus
#undef _Static_assert
#endif
}

